<?php
namespace App\Http\Controllers\Api;
use App\Domain\Accounting\Services\FinancialReports;use App\Http\Controllers\Controller;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;
class AccountingReportController extends Controller{public function subsidiary(Request $request,FinancialReports $reports):JsonResponse{$d=$request->validate(['dimension'=>['required','in:member,loan,branch'],'id'=>['required','ulid'],'from'=>['required','date'],'to'=>['required','date','after_or_equal:from']]);return response()->json($reports->subsidiaryLedger($d['dimension'],$d['id'],$d['from'],$d['to']));}public function trialBalance(Request $request,FinancialReports $reports):JsonResponse{$d=$request->validate(['from'=>['required','date'],'to'=>['required','date','after_or_equal:from']]);return response()->json($reports->trialBalance($d['from'],$d['to']));}public function incomeStatement(Request $request,FinancialReports $reports):JsonResponse{$d=$request->validate(['from'=>['required','date'],'to'=>['required','date','after_or_equal:from']]);return response()->json($reports->incomeStatement($d['from'],$d['to']));}public function balanceSheet(Request $request,FinancialReports $reports):JsonResponse{$d=$request->validate(['as_of'=>['required','date']]);return response()->json($reports->balanceSheet($d['as_of']));}}
